## Security Review: app.js

### Current Issues & Recommendations

#### 1. **Missing Error Handling Middleware** ⚠️ Critical
Your application has no error handling. Any unhandled error will crash the server.

```javascript
// Add global error handler
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production' 
      ? 'Internal Server Error' 
      : err.message
  });
});
```

#### 2. **Missing Security Headers** ⚠️ High Priority
No helmet middleware to set security headers (X-Frame-Options, X-Content-Type-Options, etc.)

```javascript
const helmet = require('helmet');
app.use(helmet());
```

#### 3. **No Input Validation** ⚠️ Medium Priority
Even for GET endpoints, validate query parameters if you expand the API:

```javascript
const { query, validationResult } = require('express-validator');

app.get('/users', 
  query('limit').optional().isInt({ min: 1, max: 100 }),
  (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }
    // ... handler
  }
);
```

#### 4. **No Rate Limiting** ⚠️ High Priority
Vulnerable to DoS attacks.

```javascript
const rateLimit = require('express-rate-limit');

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP'
});

app.use(limiter);
```

#### 5. **Information Disclosure in Health Endpoint** ⚠️ Low Priority
The timestamp reveals server activity patterns.

```javascript
app.get('/health', (req, res) => {
  res.json({ status: 'ok' }); // Remove timestamp
});
```

#### 6. **No CORS Configuration** ⚠️ Medium Priority
Allow only trusted origins:

```javascript
const cors = require('cors');

app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') || 'http://localhost:3000',
  credentials: true
}));
```

#### 7. **No Request Logging/Monitoring** ⚠️ Medium Priority
Can't detect attacks without logs:

```javascript
const morgan = require('morgan');
app.use(morgan('combined')); // Use 'combined' for detailed logging
```

#### 8. **Missing Request Size Limits** ⚠️ Medium Priority
Vulnerable to large payload attacks:

```javascript
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ limit: '10kb', extended: false }));
```

#### 9. **No Unhandled Rejection Handler** ⚠️ High Priority
```javascript
process.on('unhandledRejection', (reason, promise) => {
  console.error('Unhandled Rejection at:', promise, 'reason:', reason);
  process.exit(1);
});
```

### Improved Version

Here's a hardened version of your app:

```javascript
const express = require('express');
const helmet = require('helmet');
const cors = require('cors');
const rateLimit = require('express-rate-limit');
const morgan = require('morgan');

const app = express();

// Security middleware
app.use(helmet());
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS || 'http://localhost:3000',
  credentials: true
}));

// Request size limits
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ limit: '10kb', extended: false }));

// Logging
app.use(morgan(process.env.NODE_ENV === 'production' ? 'combined' : 'dev'));

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  message: 'Too many requests from this IP',
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// Routes
app.get('/health', (req, res) => {
  res.json({ status: 'ok' });
});

app.get('/users', (req, res) => {
  try {
    res.json([
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ]);
  } catch (error) {
    res.status(500).json({ error: 'Failed to fetch users' });
  }
});

// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

// Global error handler (must be last)
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production' 
      ? 'Internal Server Error' 
      : err.message
  });
});

// Handle unhandled rejections
process.on('unhandledRejection', (reason, promise) => {
  console.error('Unhandled Rejection:', reason);
  process.exit(1);
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});

module.exports = app;
```

### Dependencies to Add
```json
{
  "helmet": "^7.1.0",
  "cors": "^2.8.5",
  "express-rate-limit": "^7.1.0",
  "morgan": "^1.10.0",
  "express-validator": "^7.0.0"
}
```

### Key Takeaways
✅ **Always** set security headers with helmet  
✅ **Always** implement rate limiting  
✅ **Always** log security events  
✅ **Always** handle errors gracefully without exposing internals  
✅ **Always** validate and sanitize inputs  
✅ **Always** limit request sizes  
✅ **Always** configure CORS properly  

